import React, { useState } from 'react';
import { motion } from 'framer-motion';
import axios from 'axios';

const Dashboard = () => {
  const [preview, setPreview] = useState(null);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setPreview(URL.createObjectURL(file));
    setLoading(true);

    const formData = new FormData();
    formData.append('file', file);

    try {
      // Connect to Flask backend on port 5000
      const res = await axios.post('http://localhost:5000/analyze', formData);
      setData(res.data);
    } catch (err) {
      alert("Network Error: Ensure the Flask server is running.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '40px', background: '#F5F7FA', minHeight: '100vh' }}>
      <header style={{ marginBottom: '30px' }}>
        <h1 style={{ color: '#1E88E5' }}>AI Diagnostic Hub</h1>
        <p style={{ color: '#64748b' }}>Brain Tumor Segmentation Viewer</p>
      </header>

      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '30px' }}>
        <div style={{ background: 'white', padding: '30px', borderRadius: '25px', boxShadow: '0 15px 35px rgba(0,0,0,0.05)' }}>
          <input type="file" onChange={handleUpload} style={{ marginBottom: '20px' }} />
          
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', background: '#000', padding: '15px', borderRadius: '20px' }}>
            {/* Original MRI Side */}
            <div style={{ position: 'relative' }}>
              {preview && <img src={preview} style={{ width: '100%', borderRadius: '10px' }} alt="Original" />}
              <span style={{ position: 'absolute', top: '10px', left: '10px', background: 'rgba(0,0,0,0.5)', color: 'white', fontSize: '10px', padding: '2px 8px', borderRadius: '4px' }}>ORIGINAL</span>
            </div>

            {/* AI Segmentation Side (The Green Overlay) */}
            <div style={{ position: 'relative' }}>
              {preview && <img src={preview} style={{ width: '100%', borderRadius: '10px', opacity: 0.8 }} alt="Base" />}
              {data?.mask && (
                <motion.img 
                  initial={{ opacity: 0 }} 
                  animate={{ opacity: 0.7 }} 
                  src={data.mask} 
                  style={{ 
                    position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
                    filter: 'hue-rotate(90deg) saturate(20) brightness(1.2)', // Turns mask green
                    mixBlendMode: 'screen', pointerEvents: 'none'
                  }} 
                />
              )}
              <span style={{ position: 'absolute', top: '10px', left: '10px', background: '#1E88E5', color: 'white', fontSize: '10px', padding: '2px 8px', borderRadius: '4px' }}>AI SEGMENTED</span>
            </div>
          </div>
        </div>

        {/* Confidence Gauge */}
        <div style={{ background: '#1E88E5', color: 'white', padding: '40px', borderRadius: '30px', textAlign: 'center' }}>
          <p style={{ textTransform: 'uppercase', fontSize: '0.8rem', opacity: 0.8 }}>Confidence Level</p>
          <h2 style={{ fontSize: '4rem', margin: '15px 0' }}>{data ? (data.confidence * 100).toFixed(1) : '00.0'}%</h2>
          <div style={{ height: '8px', background: 'rgba(255,255,255,0.2)', borderRadius: '4px', overflow: 'hidden' }}>
            <motion.div initial={{ width: 0 }} animate={{ width: data ? `${data.confidence * 100}%` : 0 }} style={{ height: '100%', background: 'white' }} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
